`<table st-table="displayedCollection" st-filtered-collection>`

```
app.directive('stFilteredCollection', function () {
  return {
    require: '^stTable',
    link: function (scope, element, attr, ctrl) {
      scope.$watch(ctrl.getFilteredCollection, function(val) {
        scope.filteredCollection = val;
      })
    }
  }
});
```

Then in your controller, you will have the filteredCollection property on your scope.

